<?php get_header(); ?>
<section class="cb-page-band"><div class="cb-container"><?php while (have_posts()) : the_post(); if (function_exists('cb_breadcrumb')) cb_breadcrumb(); ?><div class="cb-detail-heading"><p class="cb-eyebrow"><?php echo esc_html(get_post_meta(get_the_ID(), '_cb_country', true) ?: (cb_theme_lang() === 'zh' ? '项目案例' : 'CASE STUDY')); ?></p><h1><?php the_title(); ?></h1><p><?php echo esc_html(get_the_excerpt()); ?></p></div><?php echo cb_theme_image(get_the_post_thumbnail_url(get_the_ID(), 'full'), get_the_title(), 'cb-detail-hero-image', 1400, 820); ?><article class="cb-content cb-longform-content"><?php the_content(); ?><?php foreach ([['_cb_problem', cb_theme_lang() === 'zh' ? '挑战' : 'Challenge'], ['_cb_solution', cb_theme_lang() === 'zh' ? '解决方案' : 'Solution'], ['_cb_result', cb_theme_lang() === 'zh' ? '成果' : 'Result']] as $field) : $value = get_post_meta(get_the_ID(), $field[0], true); if ($value) : ?><h2><?php echo esc_html($field[1]); ?></h2><p><?php echo esc_html($value); ?></p><?php endif; endforeach; ?></article><?php endwhile; ?></div></section>
<?php get_footer(); ?>
